### **C++ PROGRAM: EVEN OR ODD CATEGORIZATION**

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
#include <ctime>

using namespace std;

// Function to categorize even and odd numbers
void categorizeNumbers(const vector<int>& numbers, vector<int>& evens, vector<int>& odds) {
    for (int num : numbers) {
        if (num % 2 == 0) {
            evens.push_back(num);
        } else {
            odds.push_back(num);
        }
    }
}

// Function to sort numbers in ascending order
void sortNumbers(vector<int>& numbers) {
    sort(numbers.begin(), numbers.end());
}

// Function to print categorized numbers
void printCategorizedNumbers(const vector<int>& evens, const vector<int>& odds) {
    cout << "EVEN NUMBERS:" << endl;
    for (int num : evens) {
        cout << num << endl;
    }
    cout << "\nODD NUMBERS:" << endl;
    for (int num : odds) {
        cout << num << endl;
    }
}

int main() {
    vector<int> numbers;
    int input;

    // Input phase
    cout << "Enter integers (type 'END' to finish):" << endl;
    while (true) {
        cin >> input;
        if (input == -1) break;
        numbers.push_back(input);
    }

    // Sort the numbers
    sortNumbers(numbers);

    // Categorize even and odd numbers
    vector<int> evens, odds;
    categorizeNumbers(numbers, evens, odds);

    // Print the categorized numbers
    printCategorizedNumbers(evens, odds);

    return 0;
}
